var countSubstrings = function(s) {
    const n = s.length;
    let count = 0;
    for (let center = 0; center < 2 * n - 1; center++) {
        let l = Math.floor(center / 2);
        let r = l + (center % 2);
        while (l >= 0 && r < n && s[l] === s[r]) {
            count++;
            l--;
            r++;
        }
    }
    return count;
};
